1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty set when given empty set", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill live cells with only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep alive a live cell with two live neighbors (survival)", () => {
15	    const result = nextGeneration([[-1, 0], [0, 0], [1, 0]]);
16	    expect(result).toContainEqual([0, 0]);
17	  });
18	  it("should keep alive a live cell with three live neighbors (survival)", () => {
19	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
20	    expect(result).toContainEqual([1, 0]);
21	  });
22	  it.todo("should kill a live cell with more than three live neighbors (overpopulation)");
23	  it.todo("should bring to life a dead cell with exactly three live neighbors (reproduction)");
24	  it.todo("should preserve a block still life unchanged");
25	  it.todo("should oscillate a vertical blinker into a horizontal blinker");
26	  it.todo("should support negative coordinates");
27	});
28

1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	const parseCellKey = (key: string): Cell => {
12	  const [xStr, yStr] = key.split(",");
13	  return [Number(xStr), Number(yStr)];
14	};
15	
16	export function nextGeneration(cells: Cell[]): Cell[] {
17	  const liveSet = new Set<string>(cells.map(([x, y]) => cellKey(x, y)));
18	
19	  const neighborCounts = new Map<string, number>();
20	  for (const [x, y] of cells) {
21	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
22	      const key = cellKey(x + dx, y + dy);
23	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
24	    }
25	  }
26	
27	  const result: Cell[] = [];
28	  for (const [key, count] of neighborCounts) {
29	    const isAlive = liveSet.has(key);
30	    if ((isAlive && count === 2) || count === 3) {
31	      result.push(parseCellKey(key));
32	    }
33	  }
34	
35	  return result;
36	}
